    public function getSourceContext(): Source
    {
        return new Source("{% use \x27bootstrap_base_layout.html.twig\x27 %}

{# Widgets #}

{% block form_widget_simple -%}
    {% if type is not defined or type not in [\x27file\x27, \x27hidden\x27] %}
        {%- set attr = attr|merge({class: (attr.class|default(\x27\x27) ~ \x27 form-control\x27)|trim}) -%}
    {% endif %}
    {{- parent() -}}
{%- endblock form_widget_simple %}

{% block button_widget -%}
    {%- set attr = attr|merge({class: (attr.class|default(\x27btn-default\x27) ~ \x27 btn\x27)|trim}) -%}
    {{- parent() -}}
{%- endblock button_widget %}

{% block money_widget -%}
    {% set prepend = not (money_pattern starts with \x27{{\x27) %}
    {% set append = not (money_pattern ends with \x27}}\x27) %}
    {% if prepend or append %}
        <div class=\"input-group\">
            {% if prepend %}
                <span class=\"input-group-addon\">{{ money_pattern|form_encode_currency }}</span>
            {% endif %}
            {{- block(\x27form_widget_simple\x27) -}}
            {% if append %}
                <span class=\"input-group-addon\">{{ money_pattern|form_encode_currency }}</span>
            {% endif %}
        </div>
    {% else %}
        {{- block(\x27form_widget_simple\x27) -}}
    {% endif %}
{%- endblock money_widget %}

{% block checkbox_widget -%}
    {%- set parent_label_class = parent_label_class|default(label_attr.class|default(\x27\x27)) -%}
    {% if \x27checkbox-inline\x27 in parent_label_class %}
        {{- form_label(form, null, {widget: parent()}) -}}
    {% else -%}
        <div class=\"checkbox\">
            {{- form_label(form, null, {widget: parent()}) -}}
        </div>
    {%- endif -%}
{%- endblock checkbox_widget %}

{% block radio_widget -%}
    {%- set parent_label_class = parent_label_class|default(label_attr.class|default(\x27\x27)) -%}
    {%- if \x27radio-inline\x27 in parent_label_class -%}
        {{- form_label(form, null, {widget: parent()}) -}}
    {%- else -%}
        <div class=\"radio\">
            {{- form_label(form, null, {widget: parent()}) -}}
        </div>
    {%- endif -%}
{%- endblock radio_widget %}

{% block choice_widget_collapsed -%}
    {%- set attr = attr|merge({class: (attr.class|default(\x27\x27) ~ \x27 form-control\x27)|trim}) -%}
    {{- parent() -}}
{%- endblock choice_widget_collapsed %}

{# Labels #}

{% block form_label -%}
    {%- set label_attr = label_attr|merge({class: (label_attr.class|default(\x27\x27) ~ \x27 control-label\x27)|trim}) -%}
    {{- parent() -}}
{%- endblock form_label %}

{% block choice_label -%}
    {# remove the checkbox-inline and radio-inline class, it\x27s only useful for embed labels #}
    {%- set label_attr = label_attr|merge({class: label_attr.class|default(\x27\x27)|replace({\x27checkbox-inline\x27: \x27\x27, \x27radio-inline\x27: \x27\x27})|trim}) -%}
    {{- block(\x27form_label\x27) -}}
{% endblock %}

{% block checkbox_label -%}
    {%- set label_attr = label_attr|merge({for: id}) -%}

    {{- block(\x27checkbox_radio_label\x27) -}}
{%- endblock checkbox_label %}

{% block radio_label -%}
    {%- set label_attr = label_attr|merge({for: id}) -%}

    {{- block(\x27checkbox_radio_label\x27) -}}
{%- endblock radio_label %}

{% block checkbox_radio_label -%}
    {# Do not display the label if widget is not defined in order to prevent double label rendering #}
    {%- if widget is defined -%}
        {%- if required -%}
            {%- set label_attr = label_attr|merge({class: (label_attr.class|default(\x27\x27) ~ \x27 required\x27)|trim}) -%}
        {%- endif -%}
        {%- if parent_label_class is defined -%}
            {% set embed_label_classes = parent_label_class|split(\x27 \x27)|filter(class => class in [\x27checkbox-inline\x27, \x27radio-inline\x27]) %}
            {%- set label_attr = label_attr|merge({class: (label_attr.class|default(\x27\x27) ~ \x27 \x27 ~ embed_label_classes|join(\x27 \x27))|trim}) -%}
        {% endif %}
        {%- if label is not same as(false) and not label -%}
            {%- if label_format is not empty -%}
                {%- set label = label_format|replace({
                    \x27%name%\x27: name,
                    \x27%id%\x27: id,
                }) -%}
            {%- else -%}
                {% set label = name|humanize %}
            {%- endif -%}
        {%- endif -%}
        <label{% with {attr: label_attr} %}{{ block(\x27attributes\x27) }}{% endwith %}>
            {#- if statement must be kept on the same line, to force the space between widget and label -#}
            {{- widget|raw }} {% if label is not same as(false) -%}
                {%- if translation_domain is same as(false) -%}
                    {%- if label_html is same as(false) -%}
                        {{ label -}}
                    {%- else -%}
                        {{ label|raw -}}
                    {%- endif -%}
                {%- else -%}
                    {%- if label_html is same as(false) -%}
                        {{ label|trans(label_translation_parameters, translation_domain) -}}
                    {%- else -%}
                        {{ label|trans(label_translation_parameters, translation_domain)|raw -}}
                    {%- endif -%}
                {%- endif -%}
            {%- endif -%}
        </label>
    {%- endif -%}
{%- endblock checkbox_radio_label %}

{# Rows #}

{% block form_row_render -%}
    <div{% with {attr: row_attr|merge({class: (row_attr.class|default(\x27\x27) ~ \x27 form-group\x27 ~ ((not compound or force_error|default(false)) and not valid ? \x27 has-error\x27))|trim})} %}{{ block(\x27attributes\x27) }}{% endwith %}>
        {{- form_label(form) }} {# -#}
        {{ form_widget(form, widget_attr) }} {# -#}
        {{- form_help(form) -}}
        {{ form_errors(form) }} {# -#}
    </div> {# -#}
{%- endblock form_row_render -%}

{% block button_row -%}
    <div{% with {attr: row_attr|merge({class: (row_attr.class|default(\x27\x27) ~ \x27 form-group\x27)|trim})} %}{{ block(\x27attributes\x27) }}{% endwith %}>
        {{- form_widget(form) -}}
    </div>
{%- endblock button_row %}

{% block choice_row -%}
    {% set force_error = true %}
    {{- block(\x27form_row\x27) }}
{%- endblock choice_row %}

{% block date_row -%}
    {% set force_error = true %}
    {{- block(\x27form_row\x27) }}
{%- endblock date_row %}

{% block time_row -%}
    {% set force_error = true %}
    {{- block(\x27form_row\x27) }}
{%- endblock time_row %}

{% block datetime_row -%}
    {% set force_error = true %}
    {{- block(\x27form_row\x27) }}
{%- endblock datetime_row %}

{% block checkbox_row -%}
    <div{% with {attr: row_attr|merge({class: (row_attr.class|default(\x27\x27) ~ \x27 form-group\x27 ~ (not valid ? \x27 has-error\x27))|trim})} %}{{ block(\x27attributes\x27) }}{% endwith %}>
        {{- form_widget(form) -}}
        {{- form_help(form) -}}
        {{- form_errors(form) -}}
    </div>
{%- endblock checkbox_row %}

{% block radio_row -%}
    <div{% with {attr: row_attr|merge({class: (row_attr.class|default(\x27\x27) ~ \x27 form-group\x27 ~ (not valid ? \x27 has-error\x27))|trim})} %}{{ block(\x27attributes\x27) }}{% endwith %}>
        {{- form_widget(form) -}}
        {{- form_help(form) -}}
        {{- form_errors(form) -}}
    </div>
{%- endblock radio_row %}

{# Errors #}

{% block form_errors -%}
    {% if errors|length > 0 -%}
    {% if form is not rootform %}<span class=\"help-block\">{% else %}<div class=\"alert alert-danger\">{% endif %}
    <ul class=\"list-unstyled\">
        {%- for error in errors -%}
            <li id=\"{{ id ~ \x27_error\x27 ~ loop.index }}\"><span class=\"glyphicon glyphicon-exclamation-sign\"></span> {{ error.message }}</li>
        {%- endfor -%}
    </ul>
    {% if form is not rootform %}</span>{% else %}</div>{% endif %}
    {%- endif %}
{%- endblock form_errors %}

{# Help #}

{% block form_help -%}
    {%- if help -%}
        {%- set help_attr = help_attr|merge({class: (help_attr.class|default(\x27\x27) ~ \x27 help-block\x27)|trim}) -%}
        <span id=\"{{ id }}_help\"{% with {attr: help_attr} %}{{ block(\x27attributes\x27) }}{% endwith %}>
            {%- if translation_domain is same as(false) -%}
                {%- if help_html is same as(false) -%}
                    {{- help -}}
                {%- else -%}
                    {{- help|raw -}}
                {%- endif -%}
            {%- else -%}
                {%- if help_html is same as(false) -%}
                    {{- help|trans(help_translation_parameters, translation_domain) -}}
                {%- else -%}
                    {{- help|trans(help_translation_parameters, translation_domain)|raw -}}
                {%- endif -%}
            {%- endif -%}
        </span>
    {%- endif -%}
{%- endblock form_help %}
", "bootstrap_3_layout.html.twig", "/var/www/sk-systems/vendor/symfony/twig-bridge/Resources/views/Form/bootstrap_3_layout.html.twig");
    }
